      {/* Particle 2 */}
      <div className="particle particle-1"></div>
      {/* Particle 3 */}
      <div className="particle particle-1"></div>
      {/* Particle 4 */}
      <div className="particle particle-1"></div>
      {/* Particle 5 */}
      <div className="particle particle-1"></div>
      {/* Particle 6 */}
      <div className="particle particle-1"></div>
      {/* Particle 7 */}
      <div className="particle particle-1"></div>
      {/* Particle 8 */}
      <div className="particle particle-1"></div>
      {/* Particle 9 */}
      <div className="particle particle-1"></div>
      {/* Particle 10 */}
      <div className="particle particle-1"></div>
    </div>
  );
};

export default ParticleBackground;
